{
  "sentences": [
    {
      "text": "我在圖書館複習中文。",
      "pinyin": "Wǒ zài túshūguǎn fùxí zhōngwén.",
      "pinyin_numeric": "wo3 zai4 tu2shu1guan3 fu4xi2 zhong1wen2.",
      "translation_en": "I am reviewing Chinese at the library.",
      "translation_ko": "저는 도서관에서 중국어를 복습하고 있어요."
    },
    {
      "text": "他在公司改正錯誤。",
      "pinyin": "Tā zài gōngsī gǎizhèng cuòwù.",
      "pinyin_numeric": "ta1 zai4 gong1si1 gai3zheng4 cuo4wu4.",
      "translation_en": "He is correcting mistakes at the company.",
      "translation_ko": "그는 회사에서 실수를 고치고 있어요."
    },
    {
      "text": "我們在教室寫句子。",
      "pinyin": "Wǒmen zài jiàoshì xiě jùzi.",
      "pinyin_numeric": "wo3men5 zai4 jiao4shi4 xie3 ju4zi5.",
      "translation_en": "We are writing sentences in the classroom.",
      "translation_ko": "우리는 교실에서 문장을 쓰고 있어요."
    },
    {
      "text": "她在公園複習重點。",
      "pinyin": "Tā zài gōngyuán fùxí zhòngdiǎn.",
      "pinyin_numeric": "ta1 zai4 gong1yuan2 fu4xi2 zhong4dian3.",
      "translation_en": "She is reviewing key points in the park.",
      "translation_ko": "그녀는 공원에서 중요한 점을 복습하고 있어요."
    },
    {
      "text": "你在哪裡複習弱點？",
      "pinyin": "Nǐ zài nǎlǐ fùxí ruòdiǎn?",
      "pinyin_numeric": "ni3 zai4 na3li3 fu4xi2 ruo4dian3?",
      "translation_en": "Where are you reviewing your weak points?",
      "translation_ko": "당신은 어디에서 약점을 복습하나요?"
    },
    {
      "text": "我們在餐廳說中文。",
      "pinyin": "Wǒmen zài cāntīng shuō zhōngwén.",
      "pinyin_numeric": "wo3men5 zai4 can1ting1 shuo1 zhong1wen2.",
      "translation_en": "We are speaking Chinese at the restaurant.",
      "translation_ko": "우리는 식당에서 중국어를 말하고 있어요."
    },
    {
      "text": "他在捷運上複習句子。",
      "pinyin": "Tā zài jiéyùn shàng fùxí jùzi.",
      "pinyin_numeric": "ta1 zai4 jie2yun4 shang4 fu4xi2 ju4zi5.",
      "translation_en": "He is reviewing sentences on the MRT.",
      "translation_ko": "그는 지하철에서 문장을 복습하고 있어요."
    },
    {
      "text": "她在咖啡店改正答案。",
      "pinyin": "Tā zài kāfēidiàn gǎizhèng dá'àn.",
      "pinyin_numeric": "ta1 zai4 ka1fei1dian4 gai3zheng4 da2'an4.",
      "translation_en": "She is correcting answers at the coffee shop.",
      "translation_ko": "그녀는 커피숍에서 답을 고치고 있어요."
    },
    {
      "text": "我們在學校再試一次。",
      "pinyin": "Wǒmen zài xuéxiào zài shì yī cì.",
      "pinyin_numeric": "wo3men5 zai4 xue2xiao4 zai4 shi4 yi1 ci4.",
      "translation_en": "We are trying again at school.",
      "translation_ko": "우리는 학교에서 다시 한 번 시도하고 있어요."
    },
    {
      "text": "他在家裡說得流利。",
      "pinyin": "Tā zài jiā lǐ shuō de liúlì.",
      "pinyin_numeric": "ta1 zai4 jia1 li3 shuo1 de5 liu2li4.",
      "translation_en": "He speaks fluently at home.",
      "translation_ko": "그는 집에서 유창하게 말해요."
    }
  ]
}
